{"path": "/tmp/sv-a8e8e617e4d344288ff486782bb51279/Components/Catalog/CatalogPagination.razor", "file_text": "<nav aria-label="Product catalog pagination">
    <ul class="pagination justify-content-center mt-4">
        <li class="page-item @(Page <= 1 ? "disabled" : "")">
            <button class="page-link" @onclick="() => GoToPage(Page - 1)" disabled="@(Page <= 1)">
                Previous
            </button>
        </li>
        @for (int i = 1; i <= TotalPages; i++)
        {
            var pageNum = i;
            <li class="page-item @(pageNum == Page ? "active" : "")">
                <button class="page-link" @onclick="() => GoToPage(pageNum)">
                    @pageNum
                </button>
            </li>
        }
        <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
            <button class="page-link" @onclick="() => GoToPage(Page + 1)" disabled="@(Page >= TotalPages)">
                Next
            </button>
        </li>
    </ul>
</nav>

@code {
    [Parameter] public int Page { get; set; }
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
"}

{"path": "/tmp/sv-a8e8e617e4d344288ff486782bb51279/Components/Catalog/CatalogSidebar.razor", "file_text": "<div class="catalog-sidebar p-3">
    <h5>Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Category</label>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                       checked="@IsSelected(category)"
                       @onchange="(e) => ToggleCategory(category, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label for="min-price" class="form-label fw-semibold">Min Price</label>
        <input id="min-price" type="number" class="form-control form-control-sm"
               placeholder="0" min="0" step="0.01"
               value="@_minPrice" @onchange="(e) => _minPrice = ParseDecimal(e.Value)" />
    </div>

    <div class="mb-3">
        <label for="max-price" class="form-label fw-semibold">Max Price</label>
        <input id="max-price" type="number" class="form-control form-control-sm"
               placeholder="Any" min="0" step="0.01"
               value="@_maxPrice" @onchange="(e) => _maxPrice = ParseDecimal(e.Value)" />
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="in-stock-only"
               checked="@_inStockOnly"
               @onchange="(e) => _inStockOnly = (bool)(e.Value ?? false)" />
        <label class="form-check-label fw-semibold" for="in-stock-only">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<sv_a8e8e617e4d344288ff486782bb51279.Services.ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private List<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked && !_selectedCategories.Contains(category))
            _selectedCategories.Add(category);
        else if (!isChecked)
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new sv_a8e8e617e4d344288ff486782bb51279.Services.ProductFilter(
            _selectedCategories.Count > 0 ? new List<string>(_selectedCategories) : null,
            _minPrice,
            _maxPrice,
            _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}
"}

{"path": "/tmp/sv-a8e8e617e4d344288ff486782bb51279/Components/Pages/Catalog.razor", "file_text": "@page "/catalog"
@using sv_a8e8e617e4d344288ff486782bb51279.Services
@using sv_a8e8e617e4d344288ff486782bb51279.Components.Catalog
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
    </div>
}

<div class="d-flex gap-3">
    <div style="flex: 0 0 25%; max-width: 25%;">
        <CatalogSidebar Categories="_categories"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />
    </div>

    <div style="flex: 1;">
        @if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_products.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found matching your criteria. Try adjusting the filters.
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_products"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            @if (_totalPages > 1)
            {
                <CatalogPagination Page="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    /// <summary>
    /// Invoked when a product card is clicked, allowing the parent or host to navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = categoriesTask.Result;
            var result = searchTask.Result;
            _products = result.Items;
            _totalCount = result.TotalCount;
            _currentPage = result.Page;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _products = [];
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
            _currentPage = result.Page;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _products = [];
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }
}
"}

